public class CacheRuim {
    // Mapa estático que só cresce, nunca remove nada — memory leak clássico
    private static final Map<String, byte[]> cache = new HashMap<>();

    public void guardar(String chave, byte[] dados) {
        cache.put(chave, dados); // nunca é removido, mesmo sem uso
    }
}
// Com tráfego real, isso enche a Old Generation aos poucos até OutOfMemoryError.
// Nenhuma configuração de heap resolve isso — o problema é lógico (referência viva
// pra sempre), não de tamanho de memória. Isso é exatamente por que @Cacheable
// com TTL (como o CacheConfig deste projeto) existe: cache sem expiração é um leak.

