// Lock-free — melhor pra alta contenção em operações simples
public class ContadorAtomico {
    private final AtomicInteger valor = new AtomicInteger(0);

    public void incrementar() {
        valor.incrementAndGet(); // CAS por baixo dos panos, sem bloqueio de thread
    }
}

// ReentrantLock — quando você precisa de tryLock() com timeout
public class ContadorComTimeout {
    private int valor = 0;
    private final ReentrantLock lock = new ReentrantLock();

    public boolean tentarIncrementar(long timeoutMs) throws InterruptedException {
        if (lock.tryLock(timeoutMs, TimeUnit.MILLISECONDS)) {
            try {
                valor++;
                return true;
            } finally {
                lock.unlock(); // SEMPRE libere no finally, mesmo se der exceção
            }
        }
        return false; // não conseguiu travar a tempo — desiste em vez de esperar pra sempre
    }
}

